import React from "react";
import {
  VerticalTimeline,
  VerticalTimelineElement,
} from "react-vertical-timeline-component";
import "react-vertical-timeline-component/style.min.css";

import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

const experienceData = [
  {
    title: "Senior Product Manager",
    company: "EY",
    date: "2022 - Present",
    icon: <FaBriefcase />,
    iconBgGradient: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
    contentBgGradient: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
    arrowBorderColor: "#764ba2",
  },
  {
    title: "Senior Product Manager",
    company: "J.P. Morgan",
    date: "2021 - 2022",
    icon: <FaBriefcase />,
    iconBgGradient: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)", // Mismo gradiente que EY para mantener consistencia
    contentBgGradient: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
    arrowBorderColor: "#764ba2",
  },
  {
    title: "Senior Product Manager",
    company: "ExxonMobil",
    date: "2014 - 2021",
    icon: <FaBriefcase />,
    iconBgGradient: "linear-gradient(135deg, #f7971e 0%, #ffd200 100%)",
    contentBgGradient: "linear-gradient(135deg, #f7971e 0%, #ffd200 100%)",
    arrowBorderColor: "#ffd200",
  },
  {
    title: "Senior Product Owner",
    company: "ExxonMobil",
    date: "2013 - 2014",
    icon: <FaBriefcase />,
    iconBgGradient: "linear-gradient(135deg, #f7971e 0%, #ffd200 100%)",
    contentBgGradient: "linear-gradient(135deg, #f7971e 0%, #ffd200 100%)",
    arrowBorderColor: "#ffd200",
  },
  {
    title: "Senior Scrum Master",
    company: "ExxonMobil",
    date: "2008 - 2013",
    icon: <FaBriefcase />,
    iconBgGradient: "linear-gradient(135deg, #f7971e 0%, #ffd200 100%)",
    contentBgGradient: "linear-gradient(135deg, #f7971e 0%, #ffd200 100%)",
    arrowBorderColor: "#ffd200",
  },
  {
    title: "Supervisor",
    company: "IBM",
    date: "2001 - 2008",
    icon: <FaBriefcase />,
    iconBgGradient: "linear-gradient(135deg, #434343 0%, black 100%)",
    contentBgGradient: "linear-gradient(135deg, #434343 0%, black 100%)",
    arrowBorderColor: "black",
  },
  {
    title: "Master of Systems Engineering",
    company: "Universidad Tecnologica Nacional (UTN)",
    date: "2001 - 2006",
    icon: <FaUniversity />,
    iconBgGradient: "linear-gradient(135deg, #2c3e50 0%, #4ca1af 100%)",
    contentBgGradient: "linear-gradient(135deg, #2c3e50 0%, #4ca1af 100%)",
    arrowBorderColor: "#4ca1af",
  },
  {
    title: "Microsoft Certified: Azure Fundamentals",
    company: "Azure",
    date: "2021",
    icon: <FaCloud />,
    iconBgGradient: "linear-gradient(135deg, #0072c6 0%, #00a1f1 100%)",
    contentBgGradient: "linear-gradient(135deg, #0072c6 0%, #00a1f1 100%)",
    arrowBorderColor: "#00a1f1",
  },
  {
    title: "PMI Agile Certified Practitioner (PMIACP)",
    company: "PMI",
    date: "2019",
    icon: <FaUniversity />,
    iconBgGradient: "linear-gradient(135deg, #1f4037 0%, #99f2c8 100%)",
    contentBgGradient: "linear-gradient(135deg, #1f4037 0%, #99f2c8 100%)",
    arrowBorderColor: "#99f2c8",
  },
  {
    title: "Certified SAFe® 6 Product Owner/Product Manager",
    company: "Scaled Agile",
    date: "2023 - 2024",
    icon: <FaUniversity />,
    iconBgGradient: "linear-gradient(135deg, #c1464e 0%, #f77a82 100%)",
    contentBgGradient: "linear-gradient(135deg, #c1464e 0%, #f77a82 100%)",
    arrowBorderColor: "#f77a82",
  },
  {
    title: "Certified Scrum Product Owner (CSPO)",
    company: "Scrum Alliance",
    date: "2022 - 2024",
    icon: <FaUniversity />,
    iconBgGradient: "linear-gradient(135deg, #1e40af 0%, #3b82f6 100%)",
    contentBgGradient: "linear-gradient(135deg, #1e40af 0%, #3b82f6 100%)",
    arrowBorderColor: "#3b82f6",
  },
];

export default function ExperienceTimeline() {
  return (
    <VerticalTimeline>
      {experienceData
        .sort((a, b) => {
          // Ordenar del más actual al más antiguo según año inicial
          const getStartYear = (dateStr) => {
            const match = dateStr.match(/\d{4}/);
            return match ? parseInt(match[0]) : 0;
          };
          return getStartYear(b.date) - getStartYear(a.date);
        })
        .map((exp, idx) => {
          const isLeft = idx % 2 === 0; // Para alternar lados
          const dateStyle = {
            position: "absolute",
            top: 12,
            width: 80,
            fontWeight: "bold",
            color: "white",
            textShadow: "0 0 5px rgba(0,0,0,0.7)",
            fontSize: "0.9rem",
            zIndex: 10,
            textAlign: isLeft ? "right" : "left",
            left: isLeft ? -90 : "auto",
            right: !isLeft ? -90 : "auto",
          };

          // Tamaño más pequeño para ítems University
          const contentFontSize = exp.icon.type === FaUniversity ? "0.85rem" : "1rem";

          return (
            <VerticalTimelineElement
              key={idx}
              date={<span style={dateStyle}>{exp.date}</span>}
              iconStyle={{
                background: exp.iconBgGradient,
                color: "#fff",
                boxShadow: "0 0 10px rgba(0,0,0,0.2)",
              }}
              contentStyle={{
                background: exp.contentBgGradient,
                color: "#fff",
                boxShadow: "0 4px 15px rgba(0,0,0,0.15)",
                fontSize: contentFontSize,
                width: "auto",
                maxWidth: "280px",
              }}
              contentArrowStyle={{
                borderRight: `7px solid ${exp.arrowBorderColor}`,
              }}
              style={{ marginBottom: "10px", marginTop: "10px" }}
              icon={exp.icon}
            >
              <h3 style={{ margin: "0 0 4px 0" }}>{exp.title}</h3>
              <h4 style={{ margin: 0 }}>{exp.company}</h4>
            </VerticalTimelineElement>
          );
        })}
    </VerticalTimeline>
  );
}
